        try:
            claims = JWTService._decode_token(raw_token)
        except Exception as exc:
            app_logger.warning(f"JWT decode failed: {exc}")
            raise AuthenticationError(ResponseMessages.INVALID_OR_EXPIRED_TOKEN)

