function pickType(hash: number): ValleyDecorationType | null {
  const roll = (hash % 1000) / 1000
  if (roll < 0.011) return 'tree'
  if (roll < 0.018) return 'rock'
  if (roll < 0.22) return 'flower'
  return null
}

